import{_ as a,o as e,c as o,a2 as l}from"./chunks/framework.BQ1gajhD.js";const q=JSON.parse('{"title":"雍和宫殿（大雄宝殿 / 银安殿）","description":"","frontmatter":{},"headers":[],"relativePath":"religion/yonghegong/yonghe-dadian.md","filePath":"religion/yonghegong/yonghe-dadian.md","lastUpdated":1784720050000}'),r={name:"religion/yonghegong/yonghe-dadian.md"};function i(n,t,s,d,h,g){return e(),o("div",null,[...t[0]||(t[0]=[l('<h1 id="雍和宫殿-大雄宝殿-银安殿" tabindex="-1">雍和宫殿（大雄宝殿 / 银安殿） <a class="header-anchor" href="#雍和宫殿-大雄宝殿-银安殿" aria-label="Permalink to &quot;雍和宫殿（大雄宝殿 / 银安殿）&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1669518608789-2366f3cd7a2f?w=1200&amp;q=80" alt="雍和宫殿黄瓦大殿"></p><blockquote><p>&quot;昔日银安殿，今朝大雄宫——王府正堂之上，三世佛端坐，十八罗汉列班，须弥山铜铸于庭。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>雍和宫殿是雍和宫的主殿，居全寺正中，相当于汉地寺院的大雄宝殿。其前身是雍亲王府的正殿&quot;银安殿&quot;——亲王举行大典、接见臣属的王府正堂，也是整座王府等级最高的建筑。乾隆九年（1744年）改寺后，正殿供奉三世佛，更名&quot;雍和宫殿&quot;，寺因殿名，殿以寺重。</p><p>殿内正中供奉三世佛，两侧十八罗汉肃然侍立，佛像背后为西方三圣；殿后东院落中更有一座明代铜铸须弥山，是佛教宇宙观的微缩模型，极为珍罕。</p><h2 id="建筑与景观" tabindex="-1">建筑与景观 <a class="header-anchor" href="#建筑与景观" aria-label="Permalink to &quot;建筑与景观&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">规格与内容</th></tr></thead><tbody><tr><td style="text-align:left;">殿宇规制</td><td style="text-align:left;">面阔七间，重檐歇山黄琉璃瓦顶，原王府银安殿升格</td></tr><tr><td style="text-align:left;">正中主供</td><td style="text-align:left;">三世佛：现在佛释迦牟尼居中，过去佛燃灯佛居左，未来佛弥勒佛居右</td></tr><tr><td style="text-align:left;">两侧</td><td style="text-align:left;">十八罗汉，分列东西两厢，神态各异</td></tr><tr><td style="text-align:left;">佛像背后</td><td style="text-align:left;">西方三圣（阿弥陀佛、观世音菩萨、大势至菩萨）</td></tr><tr><td style="text-align:left;">殿后东院</td><td style="text-align:left;">铜铸须弥山，明万历年间铸造，佛教宇宙模型</td></tr></tbody></table><p>三世佛代表佛教的时间观：燃灯佛为过去佛，曾为释迦授记；释迦牟尼为现在佛，娑婆世界的教主；弥勒佛为未来佛，将于未来降世度人。三佛并列，寓意佛法贯通过去、现在、未来三世。</p><h3 id="银安殿-名号由来" tabindex="-1">&quot;银安殿&quot;名号由来 <a class="header-anchor" href="#银安殿-名号由来" aria-label="Permalink to &quot;&quot;银安殿&quot;名号由来&quot;">​</a></h3><p>&quot;银安殿&quot;之名，源自金代皇宫正衙&quot;永安殿&quot;，取&quot;永保平安&quot;之意。清代亲王、郡王府邸的正殿皆沿称&quot;银安殿&quot;，是王府中举行册封、节庆、接见等重大典礼的场所，规制仅低于皇宫太和殿一等。雍亲王府的银安殿面阔七间、前出丹陛，正是亲王正殿的标准格局。王府改寺，银安殿不拆不毁，只将殿内的王座仪仗请出，换上三世金身——殿宇犹是故物，气象已属梵宫。</p><h3 id="铜铸须弥山" tabindex="-1">铜铸须弥山 <a class="header-anchor" href="#铜铸须弥山" aria-label="Permalink to &quot;铜铸须弥山&quot;">​</a></h3><p>须弥山位于雍和宫殿后的东院落，为明万历年间铸造的铜质模型，原为明代佛寺旧物，后移奉于此。山体分层，自下而上依次展现佛教宇宙观：</p><ul><li><strong>底层咸海</strong>：浩瀚海水之中分布东胜神洲、南赡部洲、西牛贺洲、北俱卢洲四大部洲及八小部洲，人类即居于南赡部洲；</li><li><strong>中层七金山</strong>：七重金山环绕主峰，层层渐低；</li><li><strong>中央主峰须弥山</strong>：上宽下窄，巍然独立，日月绕山而行；</li><li><strong>峰顶忉利天宫</strong>：帝释天（忉利天主）所居，即民间所谓&quot;三十三天&quot;。</li></ul><p>整座铜山将佛教&quot;三千大千世界&quot;的宇宙图景凝于一器，构思奇巧，是雍和宫少有人知却极珍贵的宝物。</p><h2 id="历史故事" tabindex="-1">历史故事 <a class="header-anchor" href="#历史故事" aria-label="Permalink to &quot;历史故事&quot;">​</a></h2><h3 id="银安殿改覆黄瓦" tabindex="-1">银安殿改覆黄瓦 <a class="header-anchor" href="#银安殿改覆黄瓦" aria-label="Permalink to &quot;银安殿改覆黄瓦&quot;">​</a></h3><p>雍正十三年（1735年）八月，雍正帝驾崩于圆明园，梓宫移奉雍和宫，停于银安殿。按清制，亲王殿宇用绿琉璃瓦，唯帝后可用黄瓦。为奉安梓宫，银安殿等主要殿宇一夜之间改覆黄琉璃瓦，王府规制就此升为宫殿规制。这片黄瓦，既是人子之孝，也是帝王之尊，至今覆盖殿顶近三百年。</p><h3 id="雍和-之名" tabindex="-1">&quot;雍和&quot;之名 <a class="header-anchor" href="#雍和-之名" aria-label="Permalink to &quot;&quot;雍和&quot;之名&quot;">​</a></h3><p>&quot;雍和&quot;二字，取&quot;雍穆和睦、天下和洽&quot;之意。从雍亲王府到雍和宫，再到寺院主殿，这个名字一路沿用，成为全寺之名。主殿以&quot;雍和&quot;为名，也寄寓着这座皇家寺院护国佑民、协和万邦的初衷。</p><h3 id="须弥山的明代身世" tabindex="-1">须弥山的明代身世 <a class="header-anchor" href="#须弥山的明代身世" aria-label="Permalink to &quot;须弥山的明代身世&quot;">​</a></h3><p>这座铜铸须弥山并非雍和宫原配之物。它铸于明万历年间，原供奉于明代佛寺，是当时信众集资铸造的供器。清初辗转移奉雍和宫，置于主殿东院。一件明代供器进入清代皇家寺院，恰好见证了两朝更替、佛事不绝的历史——佛门法物不问朝代，只问因缘，这也是须弥山最动人的地方。</p><h2 id="必看亮点" tabindex="-1">必看亮点 <a class="header-anchor" href="#必看亮点" aria-label="Permalink to &quot;必看亮点&quot;">​</a></h2><ul><li><strong>王府正殿规制</strong>：面阔七间、黄瓦重檐，是雍亲王府银安殿的原构，等级在京城寺院主殿中无出其右。</li><li><strong>三世佛并坐</strong>：过去燃灯、现在释迦、未来弥勒，藏传佛教寺院的典型时间佛组合。</li><li><strong>十八罗汉</strong>：东西两厢十八尊，造型生动，为清代精品。</li><li><strong>铜铸须弥山</strong>：明万历铜铸佛教宇宙模型，位于殿后东院，切勿错过。</li><li><strong>殿前香炉与经幡</strong>：庭中古柏、铜炉、经幡与黄瓦大殿相映，是雍和宫最经典的画面。</li></ul><h2 id="参观贴士" tabindex="-1">参观贴士 <a class="header-anchor" href="#参观贴士" aria-label="Permalink to &quot;参观贴士&quot;">​</a></h2><ul><li>瞻仰三世佛时，可按&quot;左过去、中现在、右未来&quot;的顺序辨认（以佛的方位为准）。</li><li>铜铸须弥山在殿后东院落，位置偏僻，多数游客径直略过，建议专程绕看。</li><li>殿内禁止拍照，殿外庭院可拍摄黄瓦红墙的经典角度。</li><li>殿前广场为信众敬香主要区域，礼佛高峰时段请有序等候、勿拥挤。</li><li>此处为寺院核心礼佛区，请保持安静，随喜信众功德。</li></ul><hr><p><strong>📍 位置</strong>：雍和宫中轴线第三进院落，全寺正中主殿 <strong>⏱️ 建议游览</strong>：20-25分钟 <strong>🔗 返回</strong>：<a href="/beijing-travel-guide/religion/yonghegong/">雍和宫概览</a></p><p><strong>⬅️ 上一殿</strong>：<a href="/beijing-travel-guide/religion/yonghegong/yonghe-men.html">雍和门（天王殿）</a> ｜ <strong>➡️ 下一殿</strong>：<a href="/beijing-travel-guide/religion/yonghegong/yongyou-dian.html">永佑殿</a></p>',29)])])}const p=a(r,[["render",i]]);export{q as __pageData,p as default};
